  if(saasApname == null || saasApname.isEmpty()) new TaskManager(apname).addDefaultTasks(user.getUserId(),bundle);

  //add default reports
  TemplateHelper th = new TemplateHelper(apname, bundle);
  TemplateHelper.Template tp = th.getTemplate(bundle.getString("userStatusReportId"));
  tp.install(user);
